import java.util.HashMap;

public class BankingAppModule {

    private HashMap<String, Double> accountBalances;

    public BankingAppModule() {
        accountBalances = new HashMap<>();
    }

    public double checkBalance(String accountNumber) {
        return accountBalances.getOrDefault(accountNumber, 0.0);
    }

    public boolean makeTransaction(String fromAccountNumber, String toAccountNumber, double amount) {
        if (accountBalances.containsKey(fromAccountNumber) && accountBalances.containsKey(toAccountNumber)) {
            double fromAccountBalance = accountBalances.get(fromAccountNumber);
            double toAccountBalance = accountBalances.get(toAccountNumber);

            if (fromAccountBalance >= amount) {
                accountBalances.put(fromAccountNumber, fromAccountBalance - amount);
                accountBalances.put(toAccountNumber, toAccountBalance + amount);
                return true;
            }
        }

        return false;
    }
}